// --- Inferencia de area (criterio del skill) --------------------------------
const AREA_KEYWORDS = [
  { area: 'Finance & Accounting', kw: ['finance','finanzas','accounting','contabilidad','cfo'] },
  { area: 'Legal & Compliance',   kw: ['legal','compliance','legales'] },
  { area: 'Operations',           kw: ['operations','operaciones'] },
  { area: 'Sales & Partnerships', kw: ['sales','comercial','partnerships'] },
  { area: 'Trading Desk',         kw: ['trading','mesa','trading desk'] },
  { area: 'Management',           kw: ['ceo','coo','management','direccion','dirección','directorio'] },
];
function inferArea(t) {
  if (!t) return null;
  // Si hay separador, el area esta despues
  let seg = t;
  const sep = t.match(/[|\/,]/);
  if (sep) seg = t.split(/[|\/,]/).pop().trim();
  const low = (seg + ' ' + t).toLowerCase();
  for (const { area, kw } of AREA_KEYWORDS) {
    if (kw.some(k => low.includes(k))) return area;
  }
  return null;
}
const area = inferArea(title);
const areaLine = area
  ? `Trabajás en *${area}*.`
  : `Sos parte del equipo de Ardua.`;

// --- Block Kit de la vista --------------------------------------------------
const blocks = [
  { type: 'header', text: { type: 'plain_text', text: `Hola ${firstName} 👋`, emoji: true } },
  { type: 'section', text: { type: 'mrkdwn',
    text: `${areaLine}\nSoy *Miles*, tu asistente de Producto en Slack. Esto es lo que puedo hacer por vos:` } },
  { type: 'divider' },
  { type: 'section', text: { type: 'mrkdwn',
    text: '*📝 Capturar requerimientos*\nCuando describís una necesidad en el canal de tu área, la convierto en un requerimiento y lo registro en Jira automáticamente.' } },
  { type: 'section', text: { type: 'mrkdwn',
    text: '*✅ Gestionar aprobaciones*\nSi un requerimiento necesita el visto bueno del líder del área, le acerco la decisión con botones para aprobar o rechazar.' } },
  { type: 'section', text: { type: 'mrkdwn',
    text: '*🔔 Avisarte cómo avanza*\nTe notifico en el hilo original cada vez que tu requerimiento cambia de estado: enviado a desarrollo, en curso, completado, y más.' } },
  { type: 'divider' },
  { type: 'context', elements: [{ type: 'mrkdwn',
    text: '💡 Para crear un requerimiento, escribime en el canal `#req-product-` de tu área o pedíselo a Claude.' }] },
];

const view = { type: 'home', blocks };

return [{ json: { user_id: userId, view: JSON.stringify(view) } }];

