const refParaHacer = rows.filter(r => r.status === 'TO REFINEMENT' && r.assignee);
const refEnCurso = rows.filter(r => r.status === 'IN REFINEMENT');
const refBloqueados = rows.filter(r => r.status === 'BLOCKED'); // refinamiento blocked se solapa; criterio simple V1

