  blocks.push(refParaHacer.length ? table('Ref · Para hacer', ['Key','Ticket'], refParaHacer.map(r=>[r.key,r.summary])) : emptyNote('_Nada asignado para refinar._'));
  blocks.push({ type:'header', text:{ type:'plain_text', text:`En curso (${refEnCurso.length})`, emoji:true } });
  blocks.push(refEnCurso.length ? table('Ref · En curso', ['Key','Ticket'], refEnCurso.map(r=>[r.key,r.summary])) : emptyNote('_Nada refinando ahora._'));
}

blocks.push({ type:'divider' });
blocks.push({ type:'header', text:{ type:'plain_text', text:isTL ? '▸ DESARROLLO' : 'Desarrollo', emoji:true } });
blocks.push({ type:'header', text:{ type:'plain_text', text:`En curso (${devEnCurso.length})`, emoji:true } });
blocks.push(devEnCurso.length ? table('Dev · En curso', ['Key','Ticket','Estado'], devEnCurso.map(r=>[r.key,r.summary,r.status])) : emptyNote('_Nada en curso._'));
blocks.push({ type:'header', text:{ type:'plain_text', text:`Disponibles (${devDisponibles.length})`, emoji:true } });
blocks.push(devDisponibles.length ? table('Dev · Disponibles', ['Key','Ticket'], devDisponibles.map(r=>[r.key,r.summary])) : emptyNote('_Sin tickets disponibles._'));
blocks.push({ type:'header', text:{ type:'plain_text', text:`Bloqueados (${devBloqueados.length})`, emoji:true } });
blocks.push(devBloqueados.length ? table('Dev · Bloqueados', ['Key','Ticket'], devBloqueados.map(r=>[r.key,r.summary])) : emptyNote('_Sin bloqueos._'));

blocks.push({ type:'divider' });
blocks.push({ type:'actions', elements:[
  { type:'button', style:'danger', text:{type:'plain_text',text:'Informar bloqueante',emoji:true}, action_id:'report_blocker', value:'blocker' }
]});
blocks.push({ type:'context', elements:[{ type:'mrkdwn', text:`Miles · ${rows.length} EWIs · datos en vivo` }] });

const view={type:'home',blocks};
return [{ json:{ user_id:userId, view:JSON.stringify(view) } }];

// ============================================================================
// miles-slack-event-router · Build JQL
// ----------------------------------------------------------------------------
// Arma el JQL segun el perfil. Una query amplia por perfil; el reparto en
// secciones se hace despues en el builder.
// Estados verificados 2026-06-06 (PWI y EWI).
// ============================================================================

const rp = $('Resolve Profile').first().json;
const profile = rp.profile;
const jiraId = rp.jira_id;
const areaId = rp.business_area_id;
const isTL = rp.is_tech_lead;

// Resolver nombre de area desde Resolve Area Name (pageId -> Name)
let areaName = null;
if (areaId) {
  const areas = $('Resolve Area Name').first().json.results || [];
  const match = areas.find(a => a.id === areaId);
  areaName = match ? (match.properties?.Name?.title?.[0]?.plain_text || null) : null;
}

function esc(s){ return String(s).replace(/"/g, '\\"'); }

let jql = '';
if (profile === 'stakeholder' || profile === 'lider') {
  // PWIs del area, activos (no Done/Deprecated)
  const area = areaName ? `"Business Area" = "${esc(areaName)}"` : 'project = PWI';
  jql = `project = PWI AND ${area} AND status NOT IN (Done, DEPRECATED) ORDER BY status ASC`;
} else if (profile === 'producto') {
  // PWIs: asignados a mi (varios estados) + disponibles (To Do sin asignar)
  const mine = jiraId ? `assignee = "${esc(jiraId)}"` : 'assignee IS EMPTY';
  jql = `project = PWI AND ( (${mine} AND status IN ("IN ANALYSIS","IN PROGRESS","To Do",BLOCKED)) OR (assignee IS EMPTY AND status = "To Do") ) ORDER BY status ASC`;
} else if (profile === 'tecnico') {
  // EWIs: desarrollo (mine in progress/code review/blocked + disponibles ready for dev)
  // si es TL, ademas refinamiento (to/in refinement). Traemos amplio y repartimos.
  const mine = jiraId ? `assignee = "${esc(jiraId)}"` : 'assignee IS EMPTY';
  const devStates = '"IN PROGRESS","CODE REVIEW",BLOCKED';
  const refStates = isTL ? ',"TO REFINEMENT","IN REFINEMENT"' : '';
  jql = `project = EWI AND ( (${mine} AND status IN (${devStates}${refStates})) OR (assignee IS EMPTY AND status IN ("READY FOR DEV"${isTL ? ',"TO REFINEMENT"' : ''})) ) ORDER BY status ASC`;
} else {
  jql = `project = PWI AND assignee IS EMPTY AND status = "To Do"`;
}

return [{ json: { jql, profile, jira_id: jiraId, area_name: areaName, is_tech_lead: isTL,
                  user_id: rp.user_id, first_name: rp.first_name } }];
